resource "azurerm_resource_group" "main" {
  name     = "rg-landing-zone-prod"
  location = "eastus2"

  tags = {
    environment = "production"
    managed_by  = "terraform"
  }
}

{
  "name": "policy-require-tags",
  "properties": {
    "policyType": "Custom",
    "mode": "Indexed",
    "parameters": {
      "tagName": {
        "type": "String",
        "metadata": {
          "displayName": "Required Tag Name"
        }
      }
    }
  }
}
